var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"그러니까 정리를 하자면......","JPN":"つまり、話をまとめると……","ENG":"Let me see if I understood you correctly...","TWN":"所以整理一下整個過程的話...."},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"미나 양은 장을 보고 돌아가던 중에 어떤 배달부 아가씨와 충돌하는 바람에 여기로 오게 되었다는 거죠?","JPN":"ミナさんは買い出しの帰り道に、ある配達員の女性とぶつかったせいでここに来たということですね？","ENG":"So you were coming home from grocery shopping when you collided with this mystery delivery girl... and that brought you here?","TWN":"米娜小姐買菜後回去的路上和送貨小姐發生了碰撞，所以才來到這裡，對吧？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"그 과정에서 덩달아 자신의 모습까지 바뀌게 됐고요.","JPN":"その過程で自分の姿も変わってしまったと。","ENG":"And along the way, your appearance changed to what it is now.","TWN":"在那過程中，連自己的樣子也跟著變了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"뭐, 그렇지.","JPN":"まあ、そうだね。","ENG":"Something like that.","TWN":"嗯，對的。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"하하, 그거 참 4월에 스테이크 굽는 것 같은 소리네요.","JPN":"ハハハ、それは4月に焼くステーキのような話ですね。","ENG":"Hah hah, this is like grilling a steak in the middle of April.","TWN":"哈哈，那真像 4月烤牛排一樣。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"스테이크가...... 뭐라고?","JPN":"ステーキが……なに？","ENG":"Grilling... what?","TWN":"說牛排…… 的什麼啊?"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"아, 저희 세계에서 쓰는 관용어구 같은 겁니다. 신경 쓰지 마세요.","JPN":"ああ、この世界でよく使われる慣用句みたいなものです。お気になさらず。","ENG":"Oh, it's just an expression we use in our world. Don't worry about it.","TWN":"啊，這是在我們這個世界的慣用語，別管了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......나도 이게 말이 안 되는 상황이란 건 알고 있어. 그렇지만 사실이라고.","JPN":"……自分でもこれがありえない状況ってことはわかっている。でも事実だもの。","ENG":"...I know this sounds completely ridiculous... but it's really what happened.","TWN":" ……我知道這情況不像話。 但目前這是事實。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"선배는 이 근처에서 배달부 여자가 뛰어가는 거 못 봤어?","JPN":"先輩はこの辺で走っていく配達員を見てない？","ENG":"Didn't you see a deliverywoman run by?","TWN":"前輩你在這附近沒看到有送貨小姐跑過去嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"글쎄요. 적어도 저는 그런 사람을 본 적이 없습니다만.","JPN":"ええ。少なくとも僕は見ていませんね。","ENG":"Well, I don't think I've seen anyone like that.","TWN":"這個嘛，至少我沒看過那樣的人。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"저희 파트장님께 한 번 물어보시는 건 어떨까요?","JPN":"うちの課長に聞くのはいかがでしょう？","ENG":"Why don't you ask our Lead Producer?","TWN":"要不問問看我們組長如何？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"겉은 좀 맹한 꼬맹이 같긴 해도, 모르는 게 없으신 분이거든요.","JPN":"見た目はちょっと抜けた感じの子どもですが、何でも知り尽くしてる方ですので。","ENG":"She may seem like a silly little kid, but she knows everything there is to know.","TWN":"雖然外表是看起來有點傻乎乎的小不點，但他可是個無所不知的人。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_NPC_FOOLSDAY_NULL","text":{"KOREA":"주시윤, 농땡이 그만 피우고 업무로 복귀하도록.","JPN":"アキヤマ・シリュウ、いい加減サボってないで仕事に戻れ。","ENG":"Stop slacking off and get back to work, Shiyoon.","TWN":"周時雲，別偷懶了，回到工作崗位上吧。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"어라? 소대장도 여기에 있었어?","JPN":"あれ？　小隊長もここにいたの？","ENG":"Huh? You're here too, Commander?","TWN":"咦？小隊長也在這裡啊？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_NPC_FOOLSDAY_NULL","text":{"KOREA":"음, 소대장이라니 무슨 소리지? 난 파트장인데.","JPN":"うん？　小隊長ってなんだ。私は課長なんだが。","ENG":"Commander? What are you talking about? I'm the Lead Producer.","TWN":"嗯，什麼叫做小隊長？我是組長。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_NPC_FOOLSDAY_NULL","text":{"KOREA":"그나저나 못 보던 얼굴이군. 새로 들어온다던 신입인가?","JPN":"ところで初めてみる顔だな。入ったばかりの新人か？","ENG":"Anyway, I haven't seen you around. Are you the new rookie?","TWN":"話說回來，好像是個生面孔啊，是新來的菜鳥嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"못 보던 얼굴이라니, 좀 섭섭하네.","JPN":"初めてみる顔って、それはちょっと悲しいな。","ENG":"You don't recognize me? Well, that's a bummer.","TWN":"什麼沒見過的生面孔，也太糟糕了吧。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"선배도 그렇고...... 왜들 그러는 거야? 철 지난 만우절 농담 같은 건가?","JPN":"先輩もそうだし……みんなどうしたの？　エイプリルフールのいたずらみたいなものでも流行ってるの？","ENG":"What's wrong with all of you? Is this some kind of a lame prank?","TWN":"前輩也是…… 大家為什麼都這樣？是過時的愚人節玩笑嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};